{"command": "cd /data/zrwang/auto-opt/utils/llvm-69803 && python3 -c "
# Test if (~x ^ y) <u ~z is equivalent to (x ^ y) >u z for unsigned
def test_unsigned(x, y, z, bits=8):
    mask = (1 << bits) - 1
    not_x = (~x) & mask
    not_z = (~z) & mask
    left = ((not_x ^ y) & mask) < (not_z & mask)
    right = ((x ^ y) & mask) > (z & mask)
    return left, right

# Test all combinations for 4-bit values
errors = []
for x in range(16):
    for y in range(16):
        for z in range(16):
            l, r = test_unsigned(x, y, z, bits=4)
            if l != r:
                errors.append((x, y, z, l, r))

print('Found', len(errors), 'counterexamples for unsigned transformation')
if errors:
    print('First 5:')
    for e in errors[:5]:
        print(f'  x={e[0]}, y={e[1]}, z={e[2]}: (~x^y)<u~z={e[3]}, (x^y)>uz={e[4]}')
""}

